void writePrettyJson(std::ostream& output, boost::json::value const& value, std::string& indent)
{
    if (value.is_object()) {
        const auto& object = value.as_object();
        if (object.empty()) {
            output << "{}";
            return;
        }

        output << "{\n";
        indent.append(4, ' ');
        for (auto iterator = object.begin(); iterator != object.end(); ++iterator) {
            output << indent << boost::json::serialize(iterator->key()) << ": ";
            writePrettyJson(output, iterator->value(), indent);
            if (std::next(iterator) != object.end()) {
                output << ',';
            }
            output << '\n';
        }
        indent.resize(indent.size() - 4);
        output << indent << '}';
        return;
    }

    if (value.is_array()) {
        const auto& array = value.as_array();
        if (array.empty()) {
            output << "[]";
            return;
        }

        output << "[\n";
        indent.append(4, ' ');
        for (auto iterator = array.begin(); iterator != array.end(); ++iterator) {
            output << indent;
            writePrettyJson(output, *iterator, indent);
            if (std::next(iterator) != array.end()) {
                output << ',';
            }
            output << '\n';
        }
        indent.resize(indent.size() - 4);
        output << indent << ']';
        return;
    }

    output << boost::json::serialize(value);
}
